INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00297', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關「法律明確性原則」或「犯罪構成要件明確性」，下列敘述何者錯誤？', '["刑罰之構成要件應以法律定之，只要法律就其構成要件授權以命令為補充規定，必然違反刑罰明確性原 則而違憲", "犯罪構成要件雖有不確定性，但只要意義並非一般人難以理解、且為受規範者所得預見，並可經由司法 審查加以確認，即不違背犯罪構成要件明確性原則", "犯罪構成要件明確性原則是罪刑法定原則內涵之一", "民國98年1月廢除之檢肅流氓條例有關「欺壓善良」、「品行惡劣」、「遊蕩無賴」等流氓之定義規定， 經司法院解釋認為違反法律明確性原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00298', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲欲行竊，侵入某住居，翻箱倒櫃物色屋內值錢財物。依我國刑法與實務見解，下列敘述何者錯誤？', '["甲侵入後，因不慎觸動警鈴，情急之下鎩羽而歸，甲成立侵入住居竊盜之普通未遂", "甲若成立侵入住居竊盜之普通未遂犯，該行為之處罰，得按既遂犯之刑減輕", "甲因看見牆上貼著「歹路毋通行」，一時心生悔意，遂空手離開盜所，甲成立侵入住居竊盜之中止未遂", "甲若成立侵入住居竊盜之中止未遂犯，該行為之處罰，得減輕或免除其刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00299', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '依刑法有關正當防衛、緊急避難之規定，下列敘述何者錯誤？', '["成立正當防衛或緊急避難時，法律效果皆為不罰", "二者皆得為他人防衛或避難", "對於公務上或業務上有特別義務者，皆不適用", "二者皆有過當得減輕或免除其刑之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00300', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '依實務見解，有關故意過失，下列敘述何者正確？', '["構成要件故意的內涵，包含行為人的不法意識", "非故意即屬過失", "刑法以處罰過失犯為原則", "行為人對於構成犯罪之事實，預見其發生而其發生並不違背其本意者，亦屬故意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00301', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '滿20歲的甲因生性膽小，不敢獨自行兇，因此邀集甫年滿16歲的乙與年滿12歲剛過生日的丙一同至便 利商店強盜，3人皆無精神障礙或心智缺陷，共得手新臺幣6,000元。依實務見解，下列敘述何者錯誤？', '["甲已滿18歲，有完全責任能力", "本案不成立結夥3人強盜罪", "丙雖甫滿12歲，仍屬無責任能力人", "乙、丙均未成年，僅得減輕其刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00302', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '父親甲在火災中只能救雙胞胎兒子其中之一，甲遂僅救出其一，這在刑法上屬何種概念？', '["義務衝突", "禁止錯誤", "依法令之行為", "原因自由行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00303', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲在森林裡打獵時，看見樹叢中有物體晃動，以為該物體是野豬而開槍射擊，豈料原來是同伴乙，而乙因 頭部中彈當場死亡。甲構成何種錯誤型態？', '["禁止錯誤", "打擊錯誤", "客體錯誤", "因果歷程錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00304', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於刑法第24條緊急避難，下列敘述何者正確？', '["須對於現在不法侵害", "須出於防衛自己或他人的權利", "須已盡力為防止行為", "須出於不得已之行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00305', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '依實務見解，關於中止犯之規定，下列敘述何者正確？', '["只要中止或防止其結果之發生者即屬之", "法律效果為不罰", "預備犯不適用之", "行為人只要因己意中止犯行，即成立中止犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00306', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何項犯罪不處罰未遂犯？', '["傷害罪", "竊盜罪", "殺人罪", "重傷罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
